const b = $input.first().json.body || $input.first().json;
const esc = v => String(v || '').replace(/'/g, "''");

const insert = `INSERT INTO vmm_ntr_requests
  (store_code, store_name, request_date, received_date, email_from, email_subject, email_message_id, status, total_items, created_at)
  VALUES
  ('${esc(b.storeCode)}','${esc(b.storeName)}','${esc(b.requestDate)}','${esc(b.receivedDate)}',
   '${esc(b.emailFrom)}','${esc(b.emailSubject)}','${esc(b.emailMessageId)}',
   'pending', ${parseInt(b.totalItems) || 0}, NOW())`;

return [{ json: { insert, body: b } }];

const requestId = $input.first().json.id;
const items = $('Build Header Insert').first().json.body.items || [];
const esc = v => String(v || '').replace(/'/g, "''");

if (!items.length) return [{ json: { requestId, noItems: true } }];

const valueRows = items.map(i =>
  `(${requestId},'${esc(i.item_article_no)}','${esc(i.item_name)}','${esc(i.last_received_date)}','${esc(i.last_received_qty)}','${esc(i.current_stock)}','${esc(i.stock_days)}','${esc(i.store_requirement)}','${esc(i.ho_recommendation)}')`
).join(',\n');

const sql = `INSERT INTO vmm_ntr_items
  (request_id, item_article_no, item_name, last_received_date, last_received_qty, current_stock, stock_days, store_requirement, ho_recommendation)
  VALUES\n${valueRows}`;

return [{ json: { requestId, insertItems: sql } }];
